CREATE VIEW `ads_wide_user_book_consume_ed_view` (`dt` COMMENT "create 分区", `product_id` COMMENT "产品id", `user_id` COMMENT "用户ID", `tp` COMMENT "1：阅币，2：礼券,3：赠送币,4:vip", `pay_type` COMMENT "解锁类型，对应dim_dic表中dic_column='pay_type'", `site_id` COMMENT "书籍语言id", `book_id` COMMENT "书籍ID", `Chapter_id` COMMENT "章节id", `corever` COMMENT "core的版本号", `mt` COMMENT "平台 0未知 1iphone 4安卓 7ipad 9书城", `ver` COMMENT "服务端版本号", `current_language` COMMENT "当前语言", `current_language2` COMMENT "注册时语言", `reg_date` COMMENT "注册时间", `reg_days` COMMENT "距离注册时间时长", `reg_country` COMMENT "注册国家", `appver` COMMENT "app版本", `sex` COMMENT "性别0未知 1男 2女 3保密", `is_negative_user` COMMENT "是否白嫖用户", `ads_type` COMMENT "用户广告标签ADSTYPE", `ads_quality` COMMENT "广告用户质量", `country_level` COMMENT "国家等级", `user_type` COMMENT "用户类型 1：CTT 2:RMT", `user_period` COMMENT "用户周期", `user_value` COMMENT "用户价值", `source` COMMENT "来源", `con_chp_amt` COMMENT "章节消费数额", `con_chp_cnt` COMMENT "章节消费次数", `con_book_cnt` COMMENT "消费次数，（1/章节个数）,用于统计用户实际消费次数,即对书的消费次数", `fst_tm` COMMENT "首次消费时间", `lst_tm` COMMENT "末次消费时间", `book_name` COMMENT "书籍名称", `channel` COMMENT "频道0:其他 1:女频 2：男频 9：图书 -99：其他", `build_time` COMMENT "书籍上传时间", `new_cname` COMMENT "分类名称", `book_nature` COMMENT "书籍来源 1：机翻 2：人工 3：原创 4：cp 5：原创拆章 6：翻译拆章 7：原创图书 8：有声书籍 9：cp翻译 0：未知", `normal_chapter_num_f` COMMENT "发布总章节数", `sexy2` COMMENT "书籍上架、下架判断：字段来源novel_book; Sexy2 >= 4 为下架状态，<4 为上架，其中，Sexy涉黄等级 4软下架 5强制下架 ,0 未涉黄;其他具体数字只是涉黄的分级，没有太多参考意义", `sign_type` COMMENT "签约类型 独家：0 买断， 1 A签；非独家：2 B签； 未签约：-1", `etl_tm` COMMENT "处理时间")
COMMENT "ads层阅读业务-消耗域用户宽表，消耗轻度汇总表(注意：数据是两份,这里是指将消耗用户以不同的角度去统计数据，一个用户既是ctt用户也是rmt用户，如果是算用户总的消耗数据，只要取其中一种用户类型就好）" AS SELECT `ads`.`a`.`dt`, `ads`.`a`.`product_id`, `ads`.`a`.`user_id`, `ads`.`a`.`tp`, `ads`.`a`.`pay_type`, `ads`.`a`.`site_id`, `ads`.`a`.`book_id`, `ads`.`a`.`Chapter_id`, `ads`.`a`.`corever`, `ads`.`a`.`mt`, `ads`.`a`.`ver`, `ads`.`a`.`current_language`, `ads`.`a`.`current_language2`, `ads`.`a`.`reg_date`, `ads`.`a`.`reg_days`, `ads`.`a`.`reg_country`, `ads`.`a`.`appver`, `ads`.`a`.`sex`, `ads`.`a`.`is_negative_user`, `ads`.`a`.`ads_type`, `ads`.`a`.`ads_quality`, `ads`.`a`.`country_level`, `ads`.`a`.`user_type`, `ads`.`a`.`user_period`, `ads`.`a`.`user_value`, `ads`.`a`.`source`, `ads`.`a`.`con_chp_amt`, `ads`.`a`.`con_chp_cnt`, `ads`.`a`.`con_book_cnt`, `ads`.`a`.`fst_tm`, `ads`.`a`.`lst_tm`, `c`.`book_name`, `c`.`Channel`, `c`.`build_time`, `c`.`new_cname`, `c`.`book_nature`, `c`.`normal_chapter_num_f`, `c`.`sexy2`, `c`.`sign_type`, `ads`.`a`.`etl_tm`
FROM `ads`.`ads_wide_user_book_consume_ed` AS `a` LEFT OUTER JOIN (SELECT `dim`.`dim_shuangwen_book_read_consume_info`.`book_id`, `dim`.`dim_shuangwen_book_read_consume_info`.`book_name`, `dim`.`dim_shuangwen_book_read_consume_info`.`Channel`, `dim`.`dim_shuangwen_book_read_consume_info`.`build_time`, `dim`.`dim_shuangwen_book_read_consume_info`.`new_cname`, `dim`.`dim_shuangwen_book_read_consume_info`.`book_nature`, `dim`.`dim_shuangwen_book_read_consume_info`.`normal_chapter_num_f`, `dim`.`dim_shuangwen_book_read_consume_info`.`sexy2`, `dim`.`dim_shuangwen_book_read_consume_info`.`sign_type`
FROM `dim`.`dim_shuangwen_book_read_consume_info`
WHERE `dim`.`dim_shuangwen_book_read_consume_info`.`product_id` != 8858) `c` ON `ads`.`a`.`book_id` = `c`.`book_id`;